parameters.jsCode:
// Filter: score >= 40, not applied, not expired, Indeed only
const jobs = $json.jobs || $json.classified || $json.results || [];
const qualified = [];

for (const job of jobs) {
  const score = job.match_score || job.score || 0;
  if (score < 40) continue;
  if (job.status === 'applied' || job.already_applied) continue;
  if (job.expired) continue;

  const platform = (job.platform || 'indeed').toLowerCase();
  if (!platform.includes('indeed')) continue;

  qualified.push({
    json: {
      id: job.id || job.job_id,
      title: job.title,
      company: job.company,
      url: job.url,
      jk: (job.url || '').match(/jk=([a-f0-9]+)/)?.[1] || '',
      platform: 'indeed',
      score,
      description: (job.description || '').substring(0, 3000),
      location: job.location || 'Remote',
      salary: job.salary || ''
    }
  });
}

if (qualified.length === 0) {
  return [{ json: { _empty: true, total_searched: jobs.length, message: 'No qualified Indeed jobs found' } }];
}

return qualified;

// Merge cover letter + job + answer engine config
const job = $('4. Any Jobs?').first().json;
const coverLetter = $json.cover_letter || $json.coverLetter || '';

return [{
  json: {
    job_url: job.url,
    jk: job.jk,
    job_title: job.title,
    company: job.company,
    cover_letter: coverLetter,
    description: job.description,
    score: job.score,
    dry_run: false
  }
}];

