// Final batch summary
const items = $input.all();
const applied = items.filter(i => i.json.status === 'applied' || i.json.application_id).length;
const failed = items.filter(i => !i.json.status || i.json.status !== 'applied').length;

return [{
  json: {
    success: true,
    total_processed: items.length,
    applied,
    failed,
    message: `Pipeline complete. Applied: ${applied}, Failed: ${failed}`,
    timestamp: new Date().toISOString()
  }
}];
